INSERT INTO public.lessons VALUES (5, 7, 'The Great Illusion: Why a Piece of Paper Can Buy a House', NULL, NULL, '[]', NULL, '[]', '[{"question": "What is the primary difference between Commodity Money and Fiat Money? ", "options": [" a) Commodity money is digital, while fiat money is physical.", "Commodity money has intrinsic value (like gold), while fiat money has value because of government decree. ", "Fiat money is always backed by gold, while commodity money is not. ", "Commodity money is only used in the barter system."], "correct_index": 1, "explanation": "Correct: b) \u2013 Fiat money relies on the \"social contract\" and trust in the issuing government, whereas commodity money is made of something that is valuable in itself\n"}, {"question": "If you are a \"Fundamental Investor\" looking at a company''s stock, what are you essentially doing with your money? ", "options": ["Giving a gift to the company. ", "Trading your \"stored labor\" (cash) for a claim on the company''s future \"work\" and profits", "Gambing on whether the paper currency will fail. ", "Creating a new barter system. "], "correct_index": 1, "explanation": "Correct: b) \u2013 Investing is the act of putting your capital (stored value) into an asset that has the potential to grow or produce more value over time"}, {"question": "Why is \"Store of Value\" a critical function of money?", "options": ["It allows you to use your earnings from today to buy something in the future. ", "It ensures that the price of bread never changes. ", "It prevents the government from printing more money. ", "t makes the money physically stronger and harder to tear. "], "correct_index": 0, "explanation": "Correct: a) \u2013 A store of value means you can delay your consumption. If money \"rotted\" like fruit, you would be forced to spend it immediately, making it impossible to save for retirement or big purchases\n."}]', NULL, 50, true, NULL, '2026-04-03 18:14:50.192631', 3, '1.1', 0, '{"type": "doc", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "If you were stranded on a deserted island with a suitcase containing $10 million in cash, would you be the richest person on Earth, or just a person with a lot of very expensive kindling?", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Think from your heart ! ! !", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "At its heart, ", "type": "text"}, {"text": "money is just a \"bridge\" for value.", "type": "text", "marks": [{"type": "bold"}]}, {"text": " Imagine you are a world-class baker who only makes bread, but today you need a new pair of shoes. If the shoemaker doesn''t want your bread, you’re stuck. In the old days, this \"barter system\" was a nightmare because you had to find someone who had what you wanted ", "type": "text"}, {"text": "and", "type": "text", "marks": [{"type": "italic"}]}, {"text": " wanted exactly what you had. To solve this, humans invented a middleman: a \"token\" that everyone agreed represented a specific amount of work or value.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Think of money as a ", "type": "text"}, {"text": "portable battery for your labor.", "type": "text", "marks": [{"type": "bold"}]}, {"text": " When you work for eight hours, you are essentially \"charging\" a battery (your bank account). Later, when you want to buy a coffee, you \"discharge\" a tiny bit of that stored energy to someone else. This allows us to trade our time and skills with anyone, anywhere, without needing to carry crates of bread or shoes around .", "type": "text"}]}, {"type": "socraticQuestionBlock", "attrs": {"answer": "Because the \"strength\" of the battery depends on how many batteries are in circulation. If the government \"prints\" more batteries (money) without more work being done, each individual battery becomes less powerful. This is what we call inflation", "question": "If money is just a \"battery\" for work, why does the price of things keep changing? "}}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Historically, we used ", "type": "text"}, {"text": "Commodity Money", "type": "text", "marks": [{"type": "bold"}]}, {"text": "—things that were actually valuable themselves, like gold or silver. If the \"money\" system collapsed, you still had the gold. Today, we mostly use ", "type": "text"}, {"text": "Fiat Money", "type": "text", "marks": [{"type": "bold"}]}, {"text": ". \"Fiat\" is a Latin word meaning \"let it be done.\" It has no intrinsic value (it’s just paper or digital pixels); it only works because a government says it''s legal tender and we all ", "type": "text"}, {"text": "trust", "type": "text", "marks": [{"type": "bold"}]}, {"text": " that story.", "type": "text"}]}, {"type": "socraticQuestionBlock", "attrs": {"answer": "Portability and growth. Gold is heavy, hard to divide, and limited in supply. Fiat money allows the economy to expand faster because the \"supply of batteries\" can be adjusted to match the growth of the population and technology .\n", "question": "Why did we switch from gold to paper if paper has no \"real\" value? "}}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Real-Life Application:", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Understanding money as a \"story of trust\" changes how you look at your finances. In the ", "type": "text"}, {"text": "stock market", "type": "text", "marks": [{"type": "bold"}]}, {"text": ", you aren''t just \"betting\" on numbers; you are trading your \"stored labor\" (cash) for a slice of a productive business that can hopefully \"recharge\" your battery faster than inflation drains it.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "When you hear news about ", "type": "text"}, {"text": "interest rates", "type": "text", "marks": [{"type": "bold"}]}, {"text": " rising, the government is essentially making it \"more expensive\" to get new batteries. This slows down spending and helps stop the value of your existing batteries from leaking away too fast (controlling inflation). As emphasized in ", "type": "text"}, {"text": "The Psychology of Money", "type": "text", "marks": [{"type": "bold"}, {"type": "italic"}]}, {"text": ", your success isn''t just about how many \"batteries\" you collect, but how you behave and manage the risks associated with them .", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Key Takeaways:", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Money is a tool, not the goal:", "type": "text", "marks": [{"type": "bold"}]}, {"text": " It is a medium of exchange that allows you to move value across time and space .", "type": "text"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Fiat vs. Commodity:", "type": "text", "marks": [{"type": "bold"}]}, {"text": " Modern money (Fiat) is backed by ", "type": "text"}, {"text": "trust and government decree", "type": "text", "marks": [{"type": "bold"}]}, {"text": ", whereas ancient money (Commodity) was backed by its own physical worth .", "type": "text"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "The Three Functions:", "type": "text", "marks": [{"type": "bold"}]}, {"text": " To be \"money,\" something must be a way to pay (medium of exchange), a way to measure price (unit of account), and a way to save for later (store of value).", "type": "text"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Financial Literacy is Protection:", "type": "text", "marks": [{"type": "bold"}]}, {"text": " Understanding that fiat money can be \"printed\" helps you realize why investing in real assets (like stocks or property) is crucial for long-term wealth.", "type": "text"}]}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "#price", "type": "text"}]}]}', 10);
INSERT INTO public.lessons VALUES (6, 7, 'The Great Disconnect: Why Price is What You Pay, but Value is What You Get', NULL, NULL, '[]', NULL, '[]', '[{"question": " A \"Value Investor\" like Warren Buffett would be most interested in a stock when", "options": ["Its price is hitting new all-time highs every day.", "ts price has fallen significantly below its calculated intrinsic value. ", "Everyone on the news is saying the company is the \"next big thing.\"", "The price is exactly the same as the intrinsic value."], "correct_index": 1, "explanation": "Correct: b) \u2013 Value investors look for a \"Margin of Safety,\" which only exists when you can buy something for less than it is worth\n."}, {"question": " Why did Nike''s stock price sink despite being a world-famous brand?", "options": ["The brand name was legally changed.", "Investors changed their \"narrative\" about the company''s future sales growth. ", "The stock market decided brand names no longer have value.", " Physical shoes were replaced by digital shoes everywhere. "], "correct_index": 1, "explanation": "Correct: b) \u2013 Prices move based on future expectations. When the sales outlook weakened, the \"story\" or narrative of the company''s value changed, leading buyers to demand a lower price\n."}]', NULL, 25, true, NULL, '2026-04-03 14:33:18.087229', 3, '1.1', 0, '{"type": "doc", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Why would an investor be thrilled to buy a stock that just crashed by 20%, while another person is terrified to touch it?", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Imagine you are walking through a hot, dusty desert. You have $10,000 in your pocket. You come across a man selling two things: a solid gold bar and a cold bottle of water. In the \"real world,\" the gold is worth thousands and the water is nearly free. But in this desert, you’d likely trade all your gold for that water. This is the first principle of value: ", "type": "text"}, {"text": "Value is not a fixed number; it is the usefulness or benefit something provides to you at a specific time.", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Price, on the other hand, is simply the ", "type": "text"}, {"text": "consensus of the crowd.", "type": "text", "marks": [{"type": "bold"}]}, {"text": " In a stock market, price is the result of a \"tug-of-war\" between millions of buyers and sellers. If more people want to buy a stock (demand) than sell it (supply), the price goes up. But just because the price goes up doesn''t mean the company actually became more \"valuable\" in that moment. As Howard Marks explains in ", "type": "text"}, {"text": "The Most Important Thing", "type": "text", "marks": [{"type": "italic"}]}, {"text": ", the most common mistake is assuming that a high price equals high value", "type": "text"}]}, {"type": "socraticQuestionBlock", "attrs": {"answer": "Rarely. The \"intrinsic value\" is based on the company''s actual ability to generate cash in the future\n. A price jump usually just reflects a change in people''s mood or expectations, not necessarily a change in the company''s actual machinery, patents, or profits.", "question": "Question: If a company''s stock price doubles in one day, has the \"intrinsic value\" of the company actually doubled? "}}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "To determine a fair price, professional investors look for ", "type": "text"}, {"text": "Intrinsic Value.", "type": "text", "marks": [{"type": "bold"}]}, {"text": " Think of this like the \"true weight\" of an object, while the market price is like a flickering shadow of that object on a wall. Sometimes the shadow looks much bigger than the object (overvalued), and sometimes it looks much smaller (undervalued). Your goal as a \"Value Investor,\" a concept championed by Benjamin Graham, is to wait for the shadow to look much smaller than the object before you buy .", "type": "text"}]}, {"type": "socraticQuestionBlock", "attrs": {"answer": "Because humans are emotional. In the short term, the stock market acts like a \"voting machine,\" reflecting popular opinion\n. In the long term, however, it acts like a \"weighing machine,\" eventually reflecting the true substance (the value) of the business.", "question": "Why do markets often \"overreact\" to news, like a CEO leaving or a small sales dip? "}}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Real-Life Application:", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "We see this play out every day in the news. For example, when ", "type": "text"}, {"text": "Nike''s stock recently sank to its lowest level since 2014", "type": "text", "marks": [{"type": "bold"}]}, {"text": " because of a weak sales outlook, the ", "type": "text"}, {"text": "price", "type": "text", "marks": [{"type": "italic"}]}, {"text": " dropped instantly. Investors were \"voting\" based on fear. A value investor, however, would ignore the falling price and ask: \"Is the Nike brand still valuable? Will people still buy their shoes in five years?\" If the answer is yes, the ", "type": "text"}, {"text": "value", "type": "text", "marks": [{"type": "italic"}]}, {"text": " might be much higher than the current ", "type": "text"}, {"text": "price", "type": "text", "marks": [{"type": "italic"}]}, {"text": ".", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "In your personal life, you apply this when buying a used car. The seller might ask for a ", "type": "text"}, {"text": "price", "type": "text", "marks": [{"type": "italic"}]}, {"text": " of $15,000, but after you check the \"narrative and numbers\" (the car’s history and condition), you might decide its ", "type": "text"}, {"text": "value", "type": "text", "marks": [{"type": "italic"}]}, {"text": " is only $12,000. You only buy when the price is equal to or lower than the value you’ve calculated.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Key Takeaways:", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Price is a Number, Value is an Estimate:", "type": "text", "marks": [{"type": "bold"}]}, {"text": " Price is what you see on the screen; value is an educated guess about future benefits .", "type": "text"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "The Emotional Gap:", "type": "text", "marks": [{"type": "bold"}]}, {"text": " Market prices fluctuate wildly due to human emotions like fear and greed, even when the underlying value of a business hasn''t changed.", "type": "text"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Intrinsic Value:", "type": "text", "marks": [{"type": "bold"}]}, {"text": " To be a successful investor, you must learn to calculate what a business is worth based on its \"numbers\" (earnings) and its \"narrative\" (future potential).", "type": "text"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Margin of Safety:", "type": "text", "marks": [{"type": "bold"}]}, {"text": " Always try to buy when the price is significantly lower than the value. This \"gap\" protects you if your estimate of value is slightly wrong.", "type": "text"}]}]}]}, {"type": "mcqBlock", "attrs": {"options": [" The definitive, true worth of the company at that moment. ", "A reflection of the company''s past performance only.", "The point where the current supply of shares meets the current demand from buyers. ", "A price set by the government to ensure fairness."], "question": " According to the principles of value investing, what is the \"Market Price\" of a stock? ", "explanation": "Correct: c) – Price is simply the meeting point of buyers and sellers in the market; it does not always reflect the true underlying value of the business\n.", "correctIndex": 2}}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "#money .", "type": "text"}]}]}', 5);


