INSERT INTO public.market_secrets VALUES (3, '“What happens to your money when the market crashes?”', '{"type": "doc", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "When the market crashes, your investments don\u2019t disappear\u2014they just become worth less because buyers are paying lower prices. It\u2019s like your house price dropping on paper. You only actually lose money if you sell at that lower price; otherwise, it can recover over tim"}]}]}', NULL, '🔑', 10, 1, true, NULL, '2026-04-03 18:31:25.367253');
INSERT INTO public.market_secrets VALUES (2, '“Why do 90% of traders lose money?”', '{"type": "doc", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "Most traders lose money because they act on "}, {"type": "text", "marks": [{"type": "bold"}], "text": "emotion instead of a plan"}, {"type": "text", "text": "."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "They buy when excited, sell when scared, and don\u2019t manage risk\u2014so small losses become big ones. The market rewards "}, {"type": "text", "marks": [{"type": "bold"}], "text": "discipline and patience"}, {"type": "text", "text": ", not quick decisions."}]}]}', NULL, '📊', 10, 0, true, NULL, '2026-04-03 18:30:04.370802');
INSERT INTO public.market_secrets VALUES (4, '“Why does the market fall right after you invest?”', '{"type": "doc", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "It feels like the market falls right after you invest, but it\u2019s not personal\u2014it\u2019s coincidence mixed with psychology."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "Markets move every second based on news, global events, big investors, and overall sentiment. When you finally decide to invest, it\u2019s often after seeing prices go up for a while. That means you\u2019re entering when many others have already bought, and the market may be due for a short-term drop."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "Also, your brain pays more attention to losses than gains. So even a small dip right after investing feels big and memorable, making it seem like the market reacted to you."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "In reality, the market doesn\u2019t know you exist. It\u2019s just continuously adjusting prices based on supply and demand."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "The key idea:"}, {"type": "hardBreak"}, {"type": "text", "text": "Short-term movements are random and unpredictable. What matters is staying invested with a long-term view, rather than reacting to every small fall."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "So it\u2019s not bad luck\u2014it\u2019s timing, human behavior, and normal market fluctuations."}]}]}', NULL, '🧠', 75, 2, true, NULL, '2026-04-03 18:32:25.385964');
INSERT INTO public.market_secrets VALUES (5, 'When the RBI increases repo rate, why do markets fall?', '{"type": "doc", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "When the Reserve Bank of India (RBI) increases the repo rate, it may look like a small technical change, but in reality it is one of the most powerful levers that can influence the entire economy\u2014and therefore the stock market. To deeply understand why markets fall, you have to see how this one decision slowly travels through banks, businesses, consumers, investors, and finally market sentiment."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "Let\u2019s start from the core. Repo rate is simply the rate at which banks borrow money from the RBI. When this rate goes up, borrowing becomes expensive for banks. Banks don\u2019t absorb this cost\u2014they pass it on. So, home loans, car loans, education loans, and business loans all become more expensive. For example, imagine someone planning to buy a house with a \u20b950 lakh loan. A small increase in interest rate can significantly increase their monthly EMI. That person may now delay the purchase or buy a smaller house. Multiply this behavior across millions of people, and you get a clear effect: demand in the economy starts slowing down."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "This slowdown in demand directly affects businesses. Think of real estate companies, automobile companies, or even consumer goods companies. If fewer people are taking loans and spending money, sales begin to drop. At the same time, companies themselves face higher borrowing costs. A company that was planning to expand\u2014open new factories, hire more employees, or invest in new projects\u2014now finds it more expensive to do so. So they either delay expansion or cancel it altogether. This creates a double impact: revenues go down and costs go up. Naturally, profits shrink."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "Now, the stock market is not about today\u2014it is about the future. Investors buy stocks based on what they expect companies will earn in the coming years. When the RBI increases the repo rate, investors immediately start adjusting their expectations. They think: \u201cIf borrowing is expensive and demand is slowing, companies will earn less in the future.\u201d Even before actual profits fall, stock prices begin to drop because expectations have changed. This is why markets often fall almost immediately after a rate hike announcement."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "There is also a very important concept called opportunity cost. When interest rates rise, safer investment options like fixed deposits and bonds start offering better returns. Suppose earlier a fixed deposit gave you 5% and stocks were expected to give 10\u201312%. The extra return justified the risk. But if FD rates rise to 7\u20138%, many investors\u2014especially large institutions\u2014start shifting money from stocks to safer options. This reduces demand for stocks, and when demand falls, prices fall."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "Let\u2019s bring in a real-world style scenario. Imagine a period when inflation is rising sharply\u2014prices of food, fuel, and daily essentials are increasing. To control this, the RBI increases the repo rate. This actually happened globally after the pandemic, when central banks, including the Federal Reserve, aggressively raised interest rates. In India too, RBI followed a similar path. During such times, markets often become volatile or fall because investors know that higher rates will slow down economic growth. Sectors like real estate, automobiles, and banking (especially loan-heavy businesses) are hit the hardest."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "Another layer to this is global money flow. Big investors, called Foreign Institutional Investors (FIIs), invest across countries. They constantly compare returns. If interest rates rise globally or in safer economies, they may pull money out of emerging markets like India. Even within India, higher rates can make debt instruments more attractive relative to equities. When FIIs start selling, it creates additional downward pressure on the market. This is why sometimes markets fall sharply even if the domestic situation seems stable\u2014because global capital is moving."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "Liquidity is another key factor. Markets need a constant flow of money to keep rising. When interest rates are low, money is easily available\u2014people borrow more, invest more, and liquidity is high. This pushes markets up. But when RBI increases rates, it is essentially tightening liquidity. Borrowing reduces, investment slows, and less money flows into the stock market. Think of liquidity as fuel for a car\u2014when fuel supply reduces, the car slows down. Similarly, when liquidity reduces, markets struggle to move up and often fall."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "Now comes the psychological angle, which is often underestimated but extremely powerful. Markets are driven not just by numbers, but by expectations and emotions. When RBI increases the repo rate, it sends a signal: \u201cInflation is high, and the economy may need to slow down to control it.\u201d This creates caution among investors. Even if the actual impact is not immediate, the fear of slowdown leads to selling. And when selling starts, it often becomes a chain reaction\u2014more people sell because others are selling."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "However, it is important to understand that not all rate hikes are bad in the long term. Sometimes, RBI increases rates to stabilize the economy and control inflation, which is actually healthy for long-term growth. But markets react negatively in the short term because they focus on immediate impact\u2014higher costs, lower profits, and reduced liquidity."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "To tie everything together, think of the economy as a machine powered by money. When money is cheap, the machine runs fast\u2014people spend, businesses expand, profits grow, and markets rise. When RBI increases the repo rate, it makes money expensive. This slows down spending, reduces business activity, lowers profits, and shifts investor preference toward safer assets. At the same time, liquidity tightens and fear increases. All these factors combine to push the market downward."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "In simple terms, markets fall after a repo rate hike not because of one direct reason, but because "}, {"type": "text", "marks": [{"type": "bold"}], "text": "the entire system slows down\u2014from the common person taking a loan to global investors moving billions of dollars"}, {"type": "text", "text": ". The market is just reflecting this slowdown even before it fully happens."}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "The deepest insight here is:"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "The stock market is not reacting to today\u2019s rate hike\u2014it is reacting to what that rate hike will do to tomorrow\u2019s economy."}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"type": "text", "text": "Once you understand this chain, you stop seeing market falls as random events and start seeing them as logical outcomes of how money flows through the system."}]}]}', NULL, '🔥', 100, 3, true, NULL, '2026-04-03 18:47:40.965141');


